const item = $input.first().json;
const raw = item.content?.parts?.[0]?.text || '';

if (!raw) {
  throw new Error('No se encontró texto en la respuesta del modelo');
}

let data;
try {
  // Intento 1: JSON directo (o envuelto en ```json)
  const limpio = raw.replace(/```json|```/g, '').trim();
  data = JSON.parse(limpio);
} catch (e) {
  // Intento 2: el modelo respondió en texto libre, extraigo con regex
  const categoria = (raw.match(/categor[ií]a:\s*(\w+)/i) || [])[1]?.toLowerCase() || 'otro';
  const prioridad = (raw.match(/prioridad:\s*(\w+)/i) || [])[1]?.toLowerCase() || 'media';
  const respuesta = raw.split(/\n\n+/).filter(p => !/^(clasificaci[oó]n|categor[ií]a|prioridad)/i.test(p)).join('\n\n').trim() || raw;
  data = { categoria, prioridad, respuesta };
}

return [{ json: data }];
